class FfiConverterTypeContextNotifier: FfiConverter<ContextNotifier, ulong> {
    public ConcurrentHandleMap<ContextNotifier> handleMap = new ConcurrentHandleMap<ContextNotifier>();
    
    public static FfiConverterTypeContextNotifier INSTANCE = new FfiConverterTypeContextNotifier();


    public override ulong Lower(ContextNotifier value) {
        return handleMap.Insert(value);
    }

    public override ContextNotifier Lift(ulong value) {
        return new ContextNotifierImpl(value);
    }

    public override ContextNotifier Read(BigEndianStream stream) {
        return Lift(stream.ReadULong());
    }

    public override int AllocationSize(ContextNotifier value) {
        return 8;
    }

    public override void Write(ContextNotifier value, BigEndianStream stream) {
        stream.WriteULong(Lower(value));
    }
}



